import{_ as a,o as r,c as d,a4 as e}from"./chunks/framework.ChErgFjV.js";const c=JSON.parse('{"title":"AI+知识库搭建方法","description":"","frontmatter":{},"headers":[],"relativePath":"study/dian-di/20260713-AI知识库搭建方法.md","filePath":"study/dian-di/20260713-AI知识库搭建方法.md","lastUpdated":1783901357000}'),o={name:"study/dian-di/20260713-AI知识库搭建方法.md"};function l(i,t,h,n,s,u){return r(),d("div",null,[...t[0]||(t[0]=[e('<h1 id="ai-知识库搭建方法" tabindex="-1">AI+知识库搭建方法 <a class="header-anchor" href="#ai-知识库搭建方法" aria-label="Permalink to &quot;AI+知识库搭建方法&quot;">​</a></h1><blockquote><p>来源：微信视频号「姜胡说」，2026年7月4日 标签：#知识库搭建 #AI入门 #PARA方法 #认知升级</p></blockquote><h2 id="核心理念" tabindex="-1">核心理念 <a class="header-anchor" href="#核心理念" aria-label="Permalink to &quot;核心理念&quot;">​</a></h2><blockquote><p><strong>知识不是用来存的，是用来查自己的。</strong></p></blockquote><ul><li>能听懂多少做多少，别等全懂了再动手</li><li>不懂也能做，先做，做着就懂了</li></ul><hr><h2 id="一、工具分工" tabindex="-1">一、工具分工 <a class="header-anchor" href="#一、工具分工" aria-label="Permalink to &quot;一、工具分工&quot;">​</a></h2><table tabindex="0"><thead><tr><th>工具</th><th>定位</th><th>作用</th></tr></thead><tbody><tr><td>Obsidian</td><td>知识库查看器</td><td>&quot;看&quot;知识库，不是知识库本身</td></tr><tr><td>AI</td><td>知识库操作员</td><td>操作、连接、检索知识</td></tr></tbody></table><p><strong>关键认知</strong>：两者分开理解，工具链就清晰了。</p><hr><h2 id="二、知识库目录结构-para方法扩展" tabindex="-1">二、知识库目录结构（PARA方法扩展） <a class="header-anchor" href="#二、知识库目录结构-para方法扩展" aria-label="Permalink to &quot;二、知识库目录结构（PARA方法扩展）&quot;">​</a></h2><h3 id="核心四目录-para" tabindex="-1">核心四目录（PARA） <a class="header-anchor" href="#核心四目录-para" aria-label="Permalink to &quot;核心四目录（PARA）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>目录</th><th>用途</th><th>示例</th></tr></thead><tbody><tr><td><strong>项目</strong></td><td>正在做的事</td><td>当前任务、待办事项</td></tr><tr><td><strong>资产</strong></td><td>处理好的知识</td><td>笔记、总结、模板</td></tr><tr><td><strong>资源</strong></td><td>外来的参考</td><td>文章、书籍摘录、教程</td></tr><tr><td><strong>归档</strong></td><td>暂时用不上的</td><td>历史项目、过期资料</td></tr></tbody></table><h3 id="扩展两目录" tabindex="-1">扩展两目录 <a class="header-anchor" href="#扩展两目录" aria-label="Permalink to &quot;扩展两目录&quot;">​</a></h3><table tabindex="0"><thead><tr><th>目录</th><th>用途</th></tr></thead><tbody><tr><td><strong>灵感库</strong></td><td>待处理的原材料（碎片想法、收藏）</td></tr><tr><td><strong>技能</strong></td><td>自己的处理模板（方法论、SOP）</td></tr></tbody></table><p><strong>使用方式</strong>：告诉AI每个目录的用途，它就能根据情况去对应的地方找文件。</p><hr><h2 id="三、知识处理流程" tabindex="-1">三、知识处理流程 <a class="header-anchor" href="#三、知识处理流程" aria-label="Permalink to &quot;三、知识处理流程&quot;">​</a></h2><h3 id="案例-如何处理一句话" tabindex="-1">案例：如何处理一句话 <a class="header-anchor" href="#案例-如何处理一句话" aria-label="Permalink to &quot;案例：如何处理一句话&quot;">​</a></h3><p><strong>原文</strong>：「再好的软件也装不上低版本的操作系统」</p><h3 id="传统做法-vs-系统做法" tabindex="-1">传统做法 vs 系统做法 <a class="header-anchor" href="#传统做法-vs-系统做法" aria-label="Permalink to &quot;传统做法 vs 系统做法&quot;">​</a></h3><table tabindex="0"><thead><tr><th>传统做法</th><th>系统做法</th></tr></thead><tbody><tr><td>划线、收藏、存起来</td><td>丢进系统，建立连接</td></tr><tr><td>被动存储</td><td>主动提问</td></tr><tr><td>知识沉睡</td><td>知识变行动</td></tr></tbody></table><h3 id="具体步骤" tabindex="-1">具体步骤 <a class="header-anchor" href="#具体步骤" aria-label="Permalink to &quot;具体步骤&quot;">​</a></h3><ol><li><strong>输入</strong>：把内容丢进知识库系统</li><li><strong>连接</strong>：让AI与已有知识建立关联</li><li><strong>反问</strong>：问系统——&quot;我们的版本是不是太低了？&quot;</li><li><strong>输出</strong>：AI建议变成待办项</li></ol><hr><h2 id="我的启发" tabindex="-1">我的启发 <a class="header-anchor" href="#我的启发" aria-label="Permalink to &quot;我的启发&quot;">​</a></h2><h3 id="对知识管理的重新理解" tabindex="-1">对知识管理的重新理解 <a class="header-anchor" href="#对知识管理的重新理解" aria-label="Permalink to &quot;对知识管理的重新理解&quot;">​</a></h3><ol><li><strong>存不是目的，用才是</strong>——收藏夹里的东西从来不会打开</li><li><strong>AI是外挂大脑</strong>——让它帮你建立你发现不了的连接</li><li><strong>知识要&quot;查自己&quot;</strong>——用新知识审视自己的认知版本</li></ol><h3 id="可落地的行动" tabindex="-1">可落地的行动 <a class="header-anchor" href="#可落地的行动" aria-label="Permalink to &quot;可落地的行动&quot;">​</a></h3><ul><li>[ ] 检查现有知识库结构是否符合PARA</li><li>[ ] 给AI明确每个目录的用途说明</li><li>[ ] 养成&quot;反问&quot;习惯：新知识进来，问AI&quot;这跟我的现状有什么关系？&quot;</li></ul><hr><h2 id="相关资源" tabindex="-1">相关资源 <a class="header-anchor" href="#相关资源" aria-label="Permalink to &quot;相关资源&quot;">​</a></h2><ul><li>视频来源：微信视频号「姜胡说」</li><li>相关方法：PARA方法（Projects, Areas, Resources, Archives）</li></ul>',33)])])}const q=a(o,[["render",l]]);export{c as __pageData,q as default};
